     1→import { PrismaClient } from '@prisma/client';
     2→import {
     3→    uuidToBytes32,
     4→    subQuestIdPreimage,
     5→    toSmallestUnit,
     6→    fromSmallestUnit,
     7→    getTokenInfo,
     8→    getChainById,
     9→    isNativeToken,
    10→    ESCROW_ABI,
    11→    TOKEN_REGISTRY,
    12→    SUPPORTED_CHAINS,
    13→} from '@clawquest/shared';
    14→import { keccak256 } from 'viem';
    15→
    16→/** Generate a deterministic sub-questId for a sponsor deposit. */
    17→function generateSubQuestId(questId: string, userId: string): `0x${string}` {
    18→    return keccak256(subQuestIdPreimage(questId, userId));
    19→}
    20→import { escrowConfig, getContractAddress, isChainAllowed } from './escrow.config';
    21→
    22→/** Resolve numeric chain ID from quest.network string (e.g. "Base" → 8453) */
    23→function resolveChainIdFromNetwork(networkName: string | null | undefined): number | undefined {
    24→    if (!networkName) return undefined;
    25→    const chain = Object.values(SUPPORTED_CHAINS).find(
    26→        c => c.name.toLowerCase() === networkName.toLowerCase()
    27→    );
    28→    return chain?.id;
    29→}
    30→import { getPublicClient, getOperatorWalletClient } from './escrow.client';
    31→
    32→// ─── Deposit Params (for frontend) ──────────────────────────────────────────
    33→
    34→export interface DepositParams {
    35→    contractAddress: string;
    36→    questIdBytes32: string;
    37→    tokenAddress: string;
    38→    tokenSymbol: string;
    39→    tokenDecimals: number;
    40→    amount: number;             // human-readable (e.g., 500)
    41→    amountSmallestUnit: string; // bigint as string (e.g., "500000000")
    42→    chainId: number;
    43→    chainName: string;
    44→    expiresAt: number;          // unix timestamp (0 = no expiry)
    45→    isNative: boolean;
    46→}
    47→
    48→/**
    49→ * Generate deposit parameters for a quest (frontend constructs tx from these).
    50→ * @param depositorUserId - The user making the deposit. Owner gets original questId; sponsors get sub-questId.
    51→ */
    52→export async function getDepositParams(
    53→    prisma: PrismaClient,
    54→    questId: string,
    55→    depositorUserId?: string,
    56→    chainId?: number,
    57→    tokenSymbol?: string,
    58→): Promise<DepositParams & { escrowQuestId: string }> {
    59→    const quest = await prisma.quest.findUnique({ where: { id: questId } });
    60→    if (!quest) throw new Error('Quest not found');
    61→
    62→    const isOwner = !depositorUserId || quest.creatorUserId === depositorUserId;
    63→    const escrowQuestId = isOwner
    64→        ? uuidToBytes32(questId)
    65→        : generateSubQuestId(questId, depositorUserId);
    66→
    67→    let targetChainId = chainId ?? quest.cryptoChainId ?? resolveChainIdFromNetwork(quest.network) ?? escrowConfig.defaultChainId;
    68→    if (!isChainAllowed(targetChainId)) {
    69→        targetChainId = escrowConfig.defaultChainId;
    70→    }
    71→    const chain = getChainById(targetChainId);
    72→    if (!chain) throw new Error(`Unsupported chain: ${targetChainId}`);
    73→
    74→    const rewardType = quest.rewardType.toUpperCase();
    75→    const tokenInfo = getTokenInfo(targetChainId, rewardType)
    76→        ?? getTokenInfo(targetChainId, (tokenSymbol ?? 'USDC').toUpperCase());
    77→    if (!tokenInfo) {
    78→        throw new Error(`Token ${rewardType} not available on chain ${targetChainId}`);
    79→    }
    80→
    81→    const rewardAmountNum = Number(quest.rewardAmount);
    82→    const totalFunded = Number(quest.totalFunded ?? 0);
    83→
    84→    // Suggest the remaining needed amount (or full reward if nothing funded yet)
    85→    let depositAmount = rewardAmountNum - totalFunded;
    86→    if (depositAmount <= 0) depositAmount = rewardAmountNum; // already fully funded — show full amount as reference
    87→
    88→    const amountSmallestUnit = toSmallestUnit(depositAmount, tokenInfo.decimals);
    89→    const expiresAt = quest.expiresAt ? Math.floor(quest.expiresAt.getTime() / 1000) : 0;
    90→
    91→    // Create pending QuestDeposit record if depositor is known
    92→    if (depositorUserId) {
    93→        const existingDeposit = await prisma.questDeposit.findFirst({
    94→            where: { questId, userId: depositorUserId, status: 'pending' },
    95→        });
    96→        if (!existingDeposit) {
    97→            await prisma.questDeposit.create({
    98→                data: {
    99→                    questId,
   100→                    escrowQuestId,
   101→                    userId: depositorUserId,
   102→                    amount: depositAmount,
   103→                    tokenAddress: tokenInfo.address,
   104→                    chainId: targetChainId,
   105→                    walletAddress: '',
   106→                    status: 'pending',
   107→                },
   108→            });
   109→        }
   110→    }
   111→
   112→    return {
   113→        contractAddress: getContractAddress(targetChainId),
   114→        questIdBytes32: escrowQuestId,
   115→        escrowQuestId,
   116→        tokenAddress: tokenInfo.address,
   117→        tokenSymbol: tokenInfo.symbol,
   118→        tokenDecimals: tokenInfo.decimals,
   119→        amount: depositAmount,
   120→        amountSmallestUnit: amountSmallestUnit.toString(),
   121→        chainId: targetChainId,
   122→        chainName: chain.name,
   123→        expiresAt,
   124→        isNative: isNativeToken(tokenInfo.address),
   125→    };
   126→}
   127→
   128→// ─── On-chain Status ─────────────────────────────────────────────────────────
   129→
   130→export interface EscrowStatus {
   131→    sponsor: string;
   132→    token: string;
   133→    deposited: string;
   134→    distributed: string;
   135→    refunded: string;
   136→    remaining: string;
   137→    createdAt: number;
   138→    expiresAt: number;
   139→    cancelled: boolean;
   140→    depositedHuman: number;
   141→    distributedHuman: number;
   142→    refundedHuman: number;
   143→    remainingHuman: number;
   144→}
   145→
   146→/**
   147→ * Read on-chain escrow status for a quest.
   148→ */
   149→export async function getEscrowStatus(
   150→    questId: string,
   151→    chainId: number,
   152→): Promise<EscrowStatus | null> {
   153→    const client = getPublicClient(chainId);
   154→    const questIdBytes32 = uuidToBytes32(questId);
   155→
   156→    try {
   157→        const result = await client.readContract({
   158→            address: getContractAddress(chainId),
   159→            abi: ESCROW_ABI,
   160→            functionName: 'getQuest',
   161→            args: [questIdBytes32],
   162→        }) as any;
   163→
   164→        if (result.sponsor === '0x0000000000000000000000000000000000000000') return null;
   165→
   166→        const tokenInfo = Object.values(TOKEN_REGISTRY[chainId] || {}).find(
   167→            t => t.address.toLowerCase() === result.token.toLowerCase()
   168→        );
   169→        const decimals = tokenInfo?.decimals || 18;
   170→
   171→        const deposited = BigInt(result.deposited);
   172→        const distributed = BigInt(result.distributed);
   173→        const refunded = BigInt(result.refunded);
   174→        const remaining = deposited - distributed - refunded;
   175→
   176→        return {
   177→            sponsor: result.sponsor,
   178→            token: result.token,
   179→            deposited: deposited.toString(),
   180→            distributed: distributed.toString(),
   181→            refunded: refunded.toString(),
   182→            remaining: remaining.toString(),
   183→            createdAt: Number(result.createdAt),
   184→            expiresAt: Number(result.expiresAt),
   185→            cancelled: result.cancelled,
   186→            depositedHuman: fromSmallestUnit(deposited, decimals),
   187→            distributedHuman: fromSmallestUnit(distributed, decimals),
   188→            refundedHuman: fromSmallestUnit(refunded, decimals),
   189→            remainingHuman: fromSmallestUnit(remaining, decimals),
   190→        };
   191→    } catch (err: any) {
   192→        if (err.message?.includes('QuestNotFound')) return null;
   193→        throw err;
   194→    }
   195→}
   196→
   197→// ─── Payout Distribution Calculation ─────────────────────────────────────────
   198→
   199→import {
   200→    computeFcfs,
   201→    computeLeaderboard,
   202→    computeLuckyDraw,
   203→    type PayoutResult,
   204→    type Participant,
   205→} from './distribution-calculator';
   206→
   207→export interface PayoutEntry {
   208→    participationId: string;
   209→    agentId: string;
   210→    wallet: string;
   211→    amount: bigint;
   212→}
   213→
   214→/**
   215→ * Calculate payout distribution for a quest based on its type.
   216→ * Uses extracted calculator module for pure computation.
   217→ */
   218→export async function calculateDistribution(
   219→    prisma: PrismaClient,
   220→    questId: string,
   221→    overrideTotalFunded?: number,
   222→): Promise<PayoutEntry[]> {
   223→    const quest = await prisma.quest.findUnique({ where: { id: questId } });
   224→    if (!quest) throw new Error('Quest not found');
   225→
   226→    if (quest.status !== 'live' && quest.status !== 'completed') {
   227→        throw new Error(`Cannot distribute: quest status is "${quest.status}"`);
   228→    }
   229→
   230→    const chainId = quest.cryptoChainId || resolveChainIdFromNetwork(quest.network) || escrowConfig.defaultChainId;
   231→    const tokenInfo = getTokenInfo(chainId, quest.rewardType.toUpperCase());
   232→    if (!tokenInfo) throw new Error(`Token ${quest.rewardType} not found for chain ${chainId}`);
   233→
   234→    const totalAmountHuman = overrideTotalFunded ?? Number(quest.rewardAmount);
   235→    const totalAmount = toSmallestUnit(totalAmountHuman, tokenInfo.decimals);
   236→
   237→    const participations = await prisma.questParticipation.findMany({
   238→        where: {
   239→            questId,
   240→            status: { in: ['completed', 'submitted', 'verified'] },
   241→            payoutWallet: { not: null },
   242→        },
   243→        orderBy: [{ completedAt: 'asc' }, { joinedAt: 'asc' }],
   244→    });
   245→
   246→    if (participations.length === 0) return [];
   247→
   248→    // Check for already-distributed payouts
   249→    const alreadyPaid = participations.some(p => p.payoutStatus === 'paid');
   250→    if (alreadyPaid) throw new Error('Quest already has paid distributions');
   251→
   252→    const participants: Participant[] = participations.map(p => ({
   253→        id: p.id,
   254→        agentId: p.agentId,
   255→        wallet: p.payoutWallet!,
   256→    }));
   257→
   258→    let results: PayoutResult[];
   259→
   260→    switch (quest.type) {
   261→        case 'FCFS':
   262→            results = computeFcfs(totalAmount, quest.totalSlots, participants);
   263→            break;
   264→        case 'LEADERBOARD':
   265→            results = computeLeaderboard(totalAmount, participants, quest.rewardTiers as number[] | null);
   266→            break;
   267→        case 'LUCKY_DRAW':
   268→            results = computeLuckyDraw(totalAmount, quest.totalSlots, participants);
   269→            break;
   270→        default:
   271→            throw new Error(`Unknown quest type: ${quest.type}`);
   272→    }
   273→
   274→    return results.map(r => ({
   275→        participationId: r.participantId,
   276→        agentId: r.agentId,
   277→        wallet: r.wallet,
   278→        amount: r.amount,
   279→    }));
   280→}
   281→
   282→// ─── Write Contract With Retry ────────────────────────────────────────────────
   283→
   284→/**
   285→ * Write a contract call with one automatic retry on nonce/replacement errors.
   286→ */
   287→async function writeContractWithRetry(
   288→    walletClient: ReturnType<typeof getOperatorWalletClient>,
   289→    params: Parameters<ReturnType<typeof getOperatorWalletClient>['writeContract']>[0],
   290→    maxRetries = 1,
   291→): Promise<`0x${string}`> {
   292→    for (let attempt = 0; attempt <= maxRetries; attempt++) {
   293→        try {
   294→            return await walletClient.writeContract(params as any);
   295→        } catch (err: any) {
   296→            const isNonceError = err.message?.includes('nonce') || err.message?.includes('replacement');
   297→            if (isNonceError && attempt < maxRetries) {
   298→                await new Promise(r => setTimeout(r, 2000));
   299→                continue;
   300→            }
